func metricIconClass(color string) string {
	switch color {
	case "emerald":
		return "w-6 h-6 text-emerald-600 dark:text-emerald-400"
	case "amber":
		return "w-6 h-6 text-amber-600 dark:text-amber-400"
	case "blue":
		return "w-6 h-6 text-blue-600 dark:text-blue-400"
	case "rose":
		return "w-6 h-6 text-rose-600 dark:text-rose-400"
	default:
		return "w-6 h-6 text-stone-600 dark:text-stone-400"
	}
}

func formatCurrency(amount float64) string {
	// Format with 2 decimal places
	str := fmt.Sprintf("%.2f", amount)

	// Split into integer and decimal parts
	parts := strings.Split(str, ".")
	intPart := parts[0]
	decPart := parts[1]

	// Add thousand separators
	var result []byte
	for i, c := range intPart {
		if i > 0 && (len(intPart)-i)%3 == 0 {
			result = append(result, ',')
		}
		result = append(result, byte(c))
	}

	return "$" + string(result) + "." + decPart
}

func getInitials(name string) string {
	if len(name) == 0 {
		return "?"
	}
	initials := ""
	words := []rune(name)
	initials += string(words[0])
	for i, r := range words {
		if r == ' ' && i+1 < len(words) {
			initials += string(words[i+1])
			break
		}
	}
	return initials
}

func currentYear() int {
	return time.Now().Year()
}

